{"code": "import json
import re

# Access the stored results from previous queries
books_key = 'var_functions.query_db:16'
reviews_key = 'var_functions.query_db:18'

# Get the results from locals()
books_result = locals().get(books_key)
reviews_result = locals().get(reviews_key)

# Load the data - handle both direct data and file paths
books = None
reviews = None

# Check if it's a string (file path) or list (direct data)
if isinstance(books_result, str):
    with open(books_result, 'r') as f:
        books = json.load(f)
else:
    books = books_result

if isinstance(reviews_result, str):
    with open(reviews_result, 'r') as f:
        reviews = json.load(f)
else:
    reviews = reviews_result

# Extract publication years from book details
publication_years = []
for book in books:
    details = book.get('details', '')
    # Look for year patterns in publication info
    year_match = re.search(r'(\d{4})', details)
    if year_match:
        year = int(year_match.group(1))
        publication_years.append((book['book_id'], year))

# Group reviews by book_id
reviews_by_book = {}
for review in reviews:
    book_id = review['purchase_id'].replace('purchaseid_', 'bookid_')
    rating = float(review['rating'])
    if book_id not in reviews_by_book:
        reviews_by_book[book_id] = []
    reviews_by_book[book_id].append(rating)

print('__RESULT__:')
print(f"Total books with year info: {len(publication_years)}")
print(f"Total reviews mapped to books: {len(reviews_by_book)}")
print(f"Sample book years: {publication_years[:5]}")

# Calculate average ratings per book
book_avg_ratings = {}
for book_id, ratings in reviews_by_book.items():
    book_avg_ratings[book_id] = sum(ratings) / len(ratings)

print(f"Sample book avg ratings: {list(book_avg_ratings.items())[:5]}")

# Create decade mapping
decade_stats = {}
for book_id, year in publication_years:
    if book_id in book_avg_ratings:
        decade = f"{(year // 10) * 10}s"
        if decade not in decade_stats:
            decade_stats[decade] = {'books': set(), 'ratings': []}
        decade_stats[decade]['books'].add(book_id)
        decade_stats[decade]['ratings'].append(book_avg_ratings[book_id])

# Filter decades with at least 10 distinct books and calculate averages
valid_decades = []
for decade, stats in decade_stats.items():
    if len(stats['books']) >= 10:
        avg_rating = sum(stats['ratings']) / len(stats['ratings'])
        valid_decades.append((decade, avg_rating, len(stats['books'])))

# Sort by average rating descending
valid_decades.sort(key=lambda x: x[1], reverse=True)

print(f"Decades with >= 10 books: {len(valid_decades)}")
print(f"Top decades: {valid_decades[:5]}")

if valid_decades:
    result = {
        'top_decade': valid_decades[0][0],
        'avg_rating': valid_decades[0][1],
        'num_books': valid_decades[0][2]
    }
else:
    result = {'error': 'No decades found with at least 10 books'}

print(json.dumps(result, indent=2))"}

